const docs = Array.isArray(msg.payload) ? msg.payload : [];
const catalogs = docs.map(d => ({
    uniqueId: d.uniqueId,
    catalogId: d.catalog?.catalogId || d.uniqueId,
    catalogName: d.catalog?.catalogName || d.catalog?.catalogId || '-',
    owner: d.catalog?.owner || '-',
    strategy: d.catalog?.strategy || 'none',
    baseEndpoint: d.catalog?.baseEndpoint || '',
    enabled: d.catalog?.enabled !== false,
    protocol: d.catalog?.protocol || 'Query interface',
    updatedAt: d.catalog?.updatedAt || '',
}));
msg.response = {
    action: 'getHarvestCatalogues',
    status: 'success',
    catalogs
};
delete msg.payload;
return msg;

const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 12; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const runId = 'run-' + Date.now().toString(36) + rnd;

const catalogues = msg.data?.catalogues || [];
const catNames = catalogues.map(c => c.catalogName).filter(Boolean);
const now = new Date();
const nowISO = now.toISOString();
const nowShort = nowISO.replace('T', ' ').slice(0, 19);

const provenance = [];
const logs = [];
const assetDetails = [];
const lcDocs = [];
let assetCounter = 0;

for (const cat of catalogues) {
    const strategy = cat.strategy || 'none';
    const catName = cat.catalogName || cat.uniqueId || 'Unknown';
    const assetCount = Math.floor(Math.random() * 15) + 5;
    for (let i = 0; i < assetCount; i++) {
        assetCounter++;
        const assetId = 'asset-' + runId + '-' + assetCounter;
        const lcId = 'lc-' + runId + '-' + assetCounter;
        const isError = Math.random() < 0.1;
        const isWarning = !isError && Math.random() < 0.1;
        const assetStatus = isError ? 'error' : 'success';
        const assetTitle = catName + ' Asset ' + assetCounter;

        assetDetails.push({
            assetId: assetId,
            title: assetTitle,
            catalogue: catName,
            status: assetStatus,
            strategy: strategy
        });

        // Build local catalogue asset document
        lcDocs.push({
            uniqueId: lcId,
            sourceAssetId: assetId,
            title: assetTitle,
            catalogue: catName,
            catalogueId: cat.uniqueId || '',
            type: 'Dataset',
            domain: catName,
            strategy: strategy,
            status: assetStatus === 'error' ? 'Error' : 'Active',
            harvestRunId: runId,
            harvestScope: msg.data?.scope || {},
            harvestedAt: nowISO,
            createdAt: nowISO,
            updatedAt: nowISO
        });

        if (!isError) {
            provenance.push({
                runId: runId,
                assetId: assetId,
                title: assetTitle,
                catalogue: catName,
                action: 'imported',
                strategy: strategy,
                timestamp: nowISO,
                status: 'success'
            });
        }

        if (isError) {
            logs.push({
                runId: runId,
                assetId: assetId,
                level: 'error',
                message: 'Failed to import asset: ' + assetTitle,
                catalogue: catName,
                timestamp: nowISO
            });
        } else if (isWarning) {
            logs.push({
                runId: runId,
                assetId: assetId,
                level: 'warning',
                message: 'Asset imported with warnings: ' + assetTitle,
                catalogue: catName,
                timestamp: nowISO
            });
        } else {
            logs.push({
                runId: runId,
                assetId: assetId,
                level: 'info',
                message: 'Successfully imported: ' + assetTitle,
                catalogue: catName,
                timestamp: nowISO
            });
        }
    }
}

const successCount = assetDetails.filter(a => a.status === 'success').length;
const errorCount = assetDetails.filter(a => a.status === 'error').length;

const run = {
    uniqueId: runId,
    catalogues: catalogues,
    catalogueName: catNames.join(', ') || 'Harvest',
    scope: msg.data?.scope || {},
    lifecycle: msg.data?.lifecycle || {},
    status: 'completed',
    startedAt: nowShort,
    completedAt: new Date(now.getTime() + 120000).toISOString().replace('T', ' ').slice(0, 19),
    duration: '2m 0s',
    totalAssets: assetCounter,
    assetsAdded: successCount,
    successCount: successCount,
    errorCount: errorCount,
    result: errorCount === 0 ? 'Success' : 'Partial',
    tool: 'Harvester',
    assets: assetDetails,
    provenance: provenance,
    logs: logs
};

// Output 1: insert harvest run (carries _harvestRun for the response)
const msg1 = {
    _harvestRun: run,
    operation: 'insertOne',
    collection: 'h_harvest_runs',
    payload: run,
    _msgid: msg._msgid,
    _uib: msg._uib,
    _socketId: msg._socketId
};

// Output 2: insert local catalogue assets (fresh msg, independent path)
if (lcDocs.length > 0) {
    const msg2 = {
        operation: 'insertMany',
        collection: 'lc_assets',
        payload: lcDocs
    };
    return [msg1, msg2];
}
return [msg1, null];

const run = msg._harvestRun || {};
delete msg._harvestRun;

msg.response = {
    action: 'startHarvest',
    status: 'success',
    run: run
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const runs = docs.map(d => {
    const r = Object.assign({}, d);
    delete r.provenance;
    delete r.logs;
    delete r.assets;
    return r;
});
runs.sort((a, b) => (b.startedAt || '').localeCompare(a.startedAt || ''));
msg.response = {
    action: 'listHarvestRuns',
    status: 'success',
    runs: runs
};
delete msg.payload;
return msg;

msg.operation = 'findOne';
msg.collection = 'h_harvest_runs';
msg.payload = { uniqueId: msg.data.runId };
return msg;

const run = msg.payload || null;
msg.response = {
    action: 'getHarvestRunDetail',
    status: 'success',
    run: run
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const logs = [];
for (const d of docs) {
    if (Array.isArray(d.logs)) {
        for (const l of d.logs) logs.push(l);
    }
}
msg.response = {
    action: 'listHarvestLogs',
    status: 'success',
    logs: logs
};
delete msg.payload;
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const provenance = [];
for (const d of docs) {
    if (Array.isArray(d.provenance)) {
        for (const p of d.provenance) provenance.push(p);
    }
}
msg.response = {
    action: 'listHarvestProvenance',
    status: 'success',
    provenance: provenance
};
delete msg.payload;
return msg;

msg.operation = 'updateOne';
msg.collection = 'h_harvest_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'paused' } }
];
msg._action = 'pauseHarvest';
return msg;

msg.operation = 'updateOne';
msg.collection = 'h_harvest_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'running' } }
];
msg._action = 'resumeHarvest';
return msg;

msg.operation = 'updateOne';
msg.collection = 'h_harvest_runs';
msg.payload = [
    { uniqueId: msg.data.runId },
    { $set: { status: 'cancelled' } }
];
msg._action = 'cancelHarvest';
return msg;

msg.response = {
    action: msg._action || 'harvestStatusUpdate',
    status: 'success'
};
delete msg.payload;
return msg;
